package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Method;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;

import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method as ReflectMethod;

class ReflectionAccessFilterHelperTest {

    private ReflectionAccessFilter filterAllow;
    private ReflectionAccessFilter filterDeny;
    private ReflectionAccessFilter filterNeutral;

    @BeforeEach
    void setUp() {
        filterAllow = mock(ReflectionAccessFilter.class);
        when(filterAllow.apply(any(Class.class))).thenReturn(FilterResult.ALLOW);

        filterDeny = mock(ReflectionAccessFilter.class);
        when(filterDeny.apply(any(Class.class))).thenReturn(FilterResult.DENY);

        filterNeutral = mock(ReflectionAccessFilter.class);
        when(filterNeutral.apply(any(Class.class))).thenReturn(FilterResult.NEUTRAL);
    }

    @Test
    void testIsJavaType_Class() throws Exception {
        // Access private static method isJavaType(String)
        ReflectMethod method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isJavaType", String.class);
        method.setAccessible(true);

        // Test with known Java type names
        assertTrue((Boolean) method.invoke(null, "java.lang.String"));
        assertTrue((Boolean) method.invoke(null, "java.util.List"));
        assertFalse((Boolean) method.invoke(null, "com.google.SomeClass"));
        assertFalse((Boolean) method.invoke(null, "android.app.Activity"));
    }

    @Test
    void testIsJavaType_Public() {
        assertTrue(ReflectionAccessFilterHelper.isJavaType(String.class));
        assertTrue(ReflectionAccessFilterHelper.isJavaType(List.class));
        assertFalse(ReflectionAccessFilterHelper.isJavaType(ReflectionAccessFilterHelper.class));
    }

    @Test
    void testIsAndroidType_Class() throws Exception {
        // Access private static method isAndroidType(String)
        ReflectMethod method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
        method.setAccessible(true);

        assertTrue((Boolean) method.invoke(null, "android.app.Activity"));
        assertTrue((Boolean) method.invoke(null, "android.widget.TextView"));
        assertFalse((Boolean) method.invoke(null, "java.lang.String"));
        assertFalse((Boolean) method.invoke(null, "com.google.SomeClass"));
    }

    @Test
    void testIsAndroidType_Public() {
        // android types usually start with "android."
        Class<?> androidTypeMock = new Object() {
            public String getName() { return "android.app.Activity"; }
        }.getClass();

        // We cannot create a real android class, so test with string method
        assertTrue(invokePrivateIsAndroidType("android.app.Activity"));
        assertFalse(ReflectionAccessFilterHelper.isAndroidType(String.class));
    }

    private boolean invokePrivateIsAndroidType(String className) {
        try {
            ReflectMethod method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
            method.setAccessible(true);
            return (Boolean) method.invoke(null, className);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }

    @Test
    void testIsAnyPlatformType() {
        assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(String.class));
        assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(List.class));
        assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(Object.class)); // likely false, check actual impl
        // Android type
        assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(new Object() {
            public String getName() { return "android.app.Activity"; }
        }.getClass()));

        // Custom class (non-java, non-android)
        assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(ReflectionAccessFilterHelperTest.class));
    }

    @Test
    void testGetFilterResult_EmptyFilters() {
        List<ReflectionAccessFilter> empty = Collections.emptyList();
        FilterResult result = ReflectionAccessFilterHelper.getFilterResult(empty, String.class);
        assertEquals(FilterResult.NEUTRAL, result);
    }

    @Test
    void testGetFilterResult_Allow() {
        List<ReflectionAccessFilter> filters = Arrays.asList(filterNeutral, filterAllow, filterDeny);
        FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
        assertEquals(FilterResult.ALLOW, result);
        verify(filterNeutral).apply(String.class);
        verify(filterAllow).apply(String.class);
        // filterDeny should not be called because allow short circuits
        verify(filterDeny, never()).apply(any());
    }

    @Test
    void testGetFilterResult_Deny() {
        List<ReflectionAccessFilter> filters = Arrays.asList(filterNeutral, filterDeny, filterAllow);
        FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
        assertEquals(FilterResult.DENY, result);
        verify(filterNeutral).apply(String.class);
        verify(filterDeny).apply(String.class);
        // filterAllow should not be called because deny short circuits
        verify(filterAllow, never()).apply(any());
    }

    @Test
    void testGetFilterResult_Neutral() {
        List<ReflectionAccessFilter> filters = Arrays.asList(filterNeutral, filterNeutral);
        FilterResult result = ReflectionAccessFilterHelper.getFilterResult(filters, String.class);
        assertEquals(FilterResult.NEUTRAL, result);
        verify(filterNeutral, times(2)).apply(String.class);
    }

    @Test
    void testCanAccess_AccessibleObjectTrue() throws Exception {
        AccessibleObject accessibleObject = mock(AccessibleObject.class);
        when(accessibleObject.isAccessible()).thenReturn(true);

        Object obj = new Object();

        assertTrue(ReflectionAccessFilterHelper.canAccess(accessibleObject, obj));
        verify(accessibleObject).isAccessible();
    }

    @Test
    void testCanAccess_AccessibleObjectFalse() throws Exception {
        AccessibleObject accessibleObject = mock(AccessibleObject.class);
        when(accessibleObject.isAccessible()).thenReturn(false);

        Object obj = new Object();

        assertFalse(ReflectionAccessFilterHelper.canAccess(accessibleObject, obj));
        verify(accessibleObject).isAccessible();
    }
}
